def test_pin_change_within_limit_succeeds(fresh_card, authed_session):
    card_id = fresh_card["id"]
    payload = {"pin": <generate_valid_pin>()}
    resp = authed_session.patch(
        f"/cards/{card_id}/pin",
        json=payload
    )
    assert resp.status_code in (200, 204), (
        f"Expected 200/204, got {resp.status_code}: {resp.text}"
    )

def test_pin_change_on_boundary_fifth_attempt_succeeds(fresh_card, authed_session):
    card_id = fresh_card["id"]
    for i in range(4):
        r = authed_session.patch(
            f"/cards/{card_id}/pin",
            json={"pin": <generate_valid_pin>()}
        )
        assert r.status_code in (200, 204), f"Setup attempt {i+1} failed: {r.status_code}"
    resp = authed_session.patch(
        f"/cards/{card_id}/pin",
        json={"pin": <generate_valid_pin>()}
    )
    assert resp.status_code in (200, 204), (
        f"5th (boundary) attempt failed with {resp.status_code}: {resp.text}"
    )

def test_pin_change_sixth_attempt_returns_429(fresh_card, authed_session):
    card_id = fresh_card["id"]
    for i in range(5):
        r = authed_session.patch(
            f"/cards/{card_id}/pin",
            json={"pin": <generate_valid_pin>()}
        )
        assert r.status_code in (200, 204), f"Setup attempt {i+1} failed: {r.status_code}"
    resp = authed_session.patch(
        f"/cards/{card_id}/pin",
        json={"pin": <generate_valid_pin>()}
    )
    assert resp.status_code == 429, (
        f"Expected 429 on 6th attempt, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert <rate_limit_error_present>(body), "No rate-limit error in response body"

def test_pin_change_state_transitions_under_to_at_to_over_limit(fresh_card, authed_session):
    card_id = fresh_card["id"]
    statuses = []
    for _ in range(6):
        r = authed_session.patch(
            f"/cards/{card_id}/pin",
            json={"pin": <generate_valid_pin>()}
        )
        statuses.append(r.status_code)
    assert all(s in (200, 204) for s in statuses[:5]), (
        f"Expected success for attempts 1-5, got {statuses[:5]}"
    )
    assert statuses[5] == 429, (
        f"Expected 429 on attempt 6, got {statuses[5]}"
    )

def test_pin_change_unowned_card_forbidden(fresh_card, authed_session, other_authed_session):
    card_id = fresh_card["id"]
    resp = other_authed_session.patch(
        f"/cards/{card_id}/pin",
        json={"pin": <generate_valid_pin>()}
    )
    assert resp.status_code in (403, 404), (
        f"Expected 403/404 for non-owner, got {resp.status_code}: {resp.text}"
    )
    verify_resp = authed_session.patch(
        f"/cards/{card_id}/pin",
        json={"pin": <generate_valid_pin>()}
    )
    assert verify_resp.status_code in (200, 204), (
        "Owner PIN change unexpectedly blocked after non-owner attempt"
    )
